package dev.yazidcv.dashboard;
import dev.yazidcv.candidate.CandidateRepository; import dev.yazidcv.cv.CvDocumentRepository; import dev.yazidcv.identity.TenantContext; import dev.yazidcv.job.JobRepository; import dev.yazidcv.review.ReviewRepository; import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationToken; import org.springframework.web.bind.annotation.*; import java.time.*; import java.util.*; import java.util.stream.*;
@RestController @RequestMapping("/api/v1/dashboard") public class DashboardController{
 private final CandidateRepository candidates; private final JobRepository jobs; private final ReviewRepository reviews; private final CvDocumentRepository cvs; private final TenantContext tenant;
 public DashboardController(CandidateRepository c,JobRepository j,ReviewRepository r,CvDocumentRepository cvs,TenantContext t){candidates=c;jobs=j;reviews=r;this.cvs=cvs;tenant=t;}
 @GetMapping public DashboardResponse dashboard(JwtAuthenticationToken auth){UUID org=tenant.organizationId(auth);LocalDate today=LocalDate.now(ZoneOffset.UTC);Instant start=today.minusDays(6).atStartOfDay().toInstant(ZoneOffset.UTC);Map<LocalDate,Long> counts=candidates.findByOrganizationIdAndCreatedAtAfter(org,start).stream().collect(Collectors.groupingBy(c->c.getCreatedAt().atZone(ZoneOffset.UTC).toLocalDate(),Collectors.counting()));List<Trend> activity=IntStream.rangeClosed(0,6).mapToObj(i->{LocalDate date=today.minusDays(6-i);return new Trend(date.getDayOfWeek().name().substring(0,3),counts.getOrDefault(date,0L));}).toList();long total=candidates.countByOrganizationIdAndActiveTrue(org),open=jobs.countByOrganizationIdAndStatus(org,"OPEN"),pending=reviews.countByOrganizationIdAndStatus(org,"PENDING"),failed=cvs.countByOrganizationIdAndStatus(org,"FAILED"),week=candidates.countByOrganizationIdAndActiveTrueAndCreatedAtAfter(org,start);return new DashboardResponse(open,total,pending,failed,week,0,activity);}
 public record Trend(String day,long applications){} public record DashboardResponse(long openJobs,long activeCandidates,long awaitingReview,long failedProcessing,long candidatesThisWeek,int averageProcessingSeconds,List<Trend> activity){}
}
